4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep live cell alive with two live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 1], [1, 1], [2, 1]]);
16	    expect(result).toContainEqual([1, 1]);
17	  });
18	  it("should keep live cell alive with three live neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
20	    expect(result).toContainEqual([0, 0]);
21	  });
22	  it("should kill live cell with more than three live neighbors (overpopulation)", () => {
23	    const result = nextGeneration([[1,1],[0,0],[1,0],[2,0],[0,1],[2,1]]);
24	    expect(result).not.toContainEqual([1,1]);
25	  });
26	  it("should reproduce dead cell with exactly three live neighbors", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("should compute next generation for blinker pattern", () => {
31	    const gen0: [number, number][] = [[0, 0], [0, 1], [0, 2]];
32	    const gen1 = nextGeneration(gen0);
33	    const sortCells = (cells: [number, number][]) =>
34	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
35	    expect(sortCells(gen1)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
36	  });
37	  it("should compute next generation for block still life pattern", () => {
38	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
39	    const sortCells = (cells: [number, number][]) =>
40	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
41	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
42	  });
43	});
